/* jshint ignore:start */
define(['jquery', 'core/log'], function ($, log) {

    "use strict"; // jshint ;_;

    log.debug('Timer: initialising');

    return {
        increment: 1,
        initseconds: 0,
        seconds: 0,
        finalseconds: 0,
        intervalhandle: null,
        callback: null,
        enabled: false,

        //for making multiple instances
        clone: function () {
            return $.extend(true, {}, this);
        },

        init: function (initseconds, callback) {
            log.debug("3 initseconds:" + initseconds);
            this.initseconds = parseInt(initseconds);
            this.seconds = parseInt(initseconds);
            this.callback = callback;
            this.enabled = true;
        },

        start: function () {
            if (!this.enabled) {
                return;
            }

            var self = this;
            this.finalseconds = 0;
            if (this.initseconds > 0) {
                this.increment = -1;
            } else {
                this.increment = 1;
            }
            this.intervalhandle = this.customSetInterval(function () {
                self.seconds = self.seconds + self.increment;
                self.finalseconds = self.finalseconds + 1;
                self.callback();
            }, 1000);
        },

        //we use a custom set interval which self adjusts for inaccuracies.
        customSetInterval: function (func, time) {
            var lastTime = Date.now(),
                lastDelay = time,
                outp = {};

            function tick()
            {
                var now = Date.now(),
                    dTime = now - lastTime;

                lastTime = now;
                lastDelay = time + lastDelay - dTime;
                outp.id = setTimeout(tick, lastDelay);
                func();

            }

            outp.id = setTimeout(tick, time);
            return outp;
        },

        disable: function () {
            this.enabled = false;
        },

        enable: function () {
            this.enabled = true;
        },

        fetch_display_time(seconds = this.seconds) {
            const hours = Math.floor(seconds / 3600);
            seconds -= hours * 3600;
            const minutes = Math.floor((seconds % 3600) / 60);
            seconds -= minutes * 60;
            const secs = seconds;

            const pad = (n) => String(n).padStart(2, '0');

            if (hours > 0) {
                return `${pad(hours)}:${pad(minutes)}:${pad(secs)}`;
            }

            return `${pad(minutes)}:${pad(secs)}`;
        },

        stop: function () {
            clearTimeout(this.intervalhandle.id);
        },

        reset: function () {
            this.seconds = this.initseconds;
        },

        pause: function () {
            this.increment = 0;
        },
        resume: function () {
            if (this.initseconds > 0) {
                this.increment = -1;
            } else {
                this.increment = 1;
            }
        }

    };//end of returned object
});//total end
